import { forwardRef } from "react";
import type { HTMLAttributes, ReactNode } from "react";
import { clsx } from "clsx";
import * as styles from "./DockSheet.css";

export interface DockSheetCustomProps {
  /**
   * The content to display inside the dock sheet
   */
  children: ReactNode;
}

export interface DockSheetProps
  extends
    Omit<HTMLAttributes<HTMLDivElement>, keyof DockSheetCustomProps>,
    DockSheetCustomProps {}

/**
 * A container component that is fixed at the bottom of the viewport.
 * Typically used for sticky action bars, navigation, or contextual actions.
 */
export const DockSheet = forwardRef<HTMLDivElement, DockSheetProps>(
  ({ children, className, ...props }, ref) => {
    return (
      <div ref={ref} className={clsx(styles.dockSheet, className)} {...props}>
        {children}
      </div>
    );
  }
);

DockSheet.displayName = "DockSheet";
